import { SECTIONS } from './configs/rewards';
import Section from './components/Section';
import styles from './App.module.css';

export default function App() {
  return (
    <div className={styles.page}>

      {/* ── Hero ───────────────────────────────────────── */}
      <header className={styles.hero}>
        <p className={styles.eyebrow}>react-rewards playground</p>
        <h1 className={styles.heading}>
          Confetti<br />
          <span className={styles.accent}>Playground</span>
        </h1>
        <p className={styles.sub}>
          Clique em qualquer botão para disparar uma animação.
          <br />
          Cada variante tem sua própria config — fácil de copiar e usar.
        </p>
      </header>

      {/* ── Reward Sections ────────────────────────────── */}
      <main className={styles.main}>
        {SECTIONS.map((section) => (
          <Section
            key={section.label}
            label={section.label}
            items={section.items}
          />
        ))}
      </main>

      {/* ── Usage Hint ─────────────────────────────────── */}
      <footer className={styles.footer}>
        <p className={styles.footerTitle}>Como usar qualquer variante</p>
        <pre className={styles.code}>{`import { useReward } from 'react-rewards';
import { CONFETTI_FIRE } from './configs/rewards';

const { reward, isAnimating } = useReward(
  CONFETTI_FIRE.id,
  CONFETTI_FIRE.type,
  CONFETTI_FIRE.config
);

<button onClick={reward} disabled={isAnimating}>
  <span id={CONFETTI_FIRE.id} />
  🔥 Disparar
</button>`}</pre>
      </footer>

    </div>
  );
}
